var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"쿨럭! ","JPN":"ガハッ！","ENG":"*Cough!* ","TWN":"咳咳！"},"stage":{"bg":"MAINSTREAM_7040010","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하아……. 하아…….","JPN":"はあ……はあ……","ENG":"Haa… Haa…","TWN":"呼……呼……"},"stage":{"bg":"MAINSTREAM_7040010","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"안색이 좋지 않군요.","JPN":"顔色がよくありませんね。","ENG":"You look rather pale.","TWN":"你的臉色好像不太好，"},"stage":{"bg":"MAINSTREAM_7040010","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"역시 피를 너무 많이 뽑아낸 걸지도 모르겠어요.","JPN":"やはり血を抜きすぎたかもしれません。","ENG":"Perhaps we've drawn too much blood from you after all.","TWN":"是因為被抽太多血的關係嗎？"},"stage":{"bg":"MAINSTREAM_7040010","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"MAINSTREAM_7040010","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"……말수가 줄어들었군요.","JPN":"……口数が減りましたね。","ENG":"…You've grown rather taciturn.","TWN":"……話也變少了呢。"},"stage":{"bg":"MAINSTREAM_7040010","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"억지로 수다스러운 척을 할 이유가 사라졌으니 당신에게도 좋은 일이겠죠.","JPN":"無理やり饒舌なふりをする理由も消えたので、あなたにとっても良いことでしょう。","ENG":"I suppose it's a good thing, as you won't have to pretend to be so chatty.","TWN":"現在不用再硬裝作很聒噪，對你來說也算是好事一件吧？"},"stage":{"bg":"MAINSTREAM_7040010","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당신은…… 꽤 내성적인 분 같으니까요.","JPN":"あなたは……とても内気な性格のようですので。","ENG":"Because it seems… you're more of an introvert.","TWN":"你……應該算是內向的人吧？"},"stage":{"bg":"MAINSTREAM_7040010","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 제가 좀…… 그런 편이긴 하죠.","JPN":"ハハ、確かに……僕ってそんなキャラなんですよね。","ENG":"Haha… Yeah, I guess I can be like that…","TWN":"哈哈～對啊……我滿內向的。"},"stage":{"bg":"MAINSTREAM_7040010","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"또 농담으로 얼버무리려 드는군요.","JPN":"また冗談で誤魔化そうとしていますね。","ENG":"And there you go trying to let jest cover your true self.","TWN":"又用開玩笑的方式來呼攏過去。"},"stage":{"bg":"MAINSTREAM_7040010","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"괜찮습니다. 곧 자신에게 솔직해져야 할 때가 올 테니까요.","JPN":"いいでしょう。もうじき自分に正直にならなければならない時が来ますから。","ENG":"Don't worry. It shall soon be time for you to be honest with yourself.","TWN":"沒關係，你很快就笑不出來了。"},"stage":{"bg":"MAINSTREAM_7040010","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"MAINSTREAM_7040010","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"기다리는 동안, 옛날 이야기를 하나 들려 드리죠.","JPN":"待つ間に、昔話を一つお聞かせしましょう。","ENG":"Let me tell you a tale while we wait.","TWN":"等待的同時我跟你說個故事吧！"},"stage":{"bg":"MAINSTREAM_7040010","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"아주 옛날에…… 구도자라고 불리던 남자가 있었습니다.","JPN":"昔々……求道者と呼ばれた男がいました。","ENG":"Long, long ago… There was a man who was called the Seeker of Truth.","TWN":"很久很久以前……有個叫作求道者的男人，"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"이런 이야기에 흔하디 흔한, 세상을 구할 사명을 지니고 태어난 자였죠.","JPN":"彼はこんな話ではありふれた、世界を救う使命を持って生まれた者でした。","ENG":"The Seeker was destined to save the world, much like other heroes of tales like this.","TWN":"在這種故事裡，一定都會有個背負拯救世界的使命而誕生的人，"},"stage":{"bg":"MAINSTREAM_7010011","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"하지만 흔히들 그렇듯이 결국 성공하진 못했습니다.","JPN":"しかし、これもまたありふれた話で、結局成し遂げることはできませんでした。","ENG":"And like those other heroes, the Seeker also failed in the end.","TWN":"不過通常都是失敗收場。"},"stage":{"bg":"MAINSTREAM_7010011","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"뭐, 현실에서도 무언가를 지키는 것 보다는 파괴하는 게 훨씬 더 쉬우니까…… ","JPN":"まあ、現実でも何かを守るより破壊するほうがずっと簡単ですから……","ENG":"Even in reality, destroying something is much easier than protecting it… ","TWN":"這也沒什麼，因為在現實世界裡也是一樣，破壞總比守護來得容易……"},"stage":{"bg":"MAINSTREAM_7010011","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그게 구도자의 잘못은 아니겠죠.","JPN":"それは求道者の過ちではないでしょう。","ENG":"But that was not the Seeker's fault.","TWN":"這完全不能怪求道者。"},"stage":{"bg":"MAINSTREAM_7010011","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"하지만 그 멍청한 남자는 포기하지 못했습니다.","JPN":"しかし、その愚かな男は諦められませんでした。","ENG":"Regardless, this foolish man could not give up.","TWN":"但問題是，那個愚蠢的男人不肯放棄。"},"stage":{"bg":"MAINSTREAM_7010011","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};